542→
543→function isOverlayObject(obj) {
544→  let current = obj;
545→  while (current) {
546→    if (current.name === 'DrawingPlaneOverlay' || current.name === 'ExtrusionPreview' ||
547→        current.name === 'PlaneGrid' || current.name === 'DrawPreview') {
548→      return true;
549→    }
550→    current = current.parent;
551→  }
552→  return false;
553→}
554→
555→function resolvePickTarget(object) {
556→  let current = object;
557→  while (current) {
558→    if (current.userData?.previewTarget) {
559→      return current.userData.previewTarget;
560→    }
561→    current = current.parent;
562→  }
563→  return null;
564→}
565→
566→function findPartIdFromObjectHit(object, project) {
567→  const target = resolvePickTarget(object);
568→  if (!target) return null;
569→  if (target.kind === 'part') return target.sourceId;
570→
571→  // Object hit - find first matching part
572→  const part = project.parts.find((p) => p.objectId === target.sourceId && p.type !== 'dimension' && p.type !== 'cutout' && p.type !== 'hole');
573→  return part?.id || null;
574→}
